final class SystemMetricsService { private ?array $cpu=null; public function collect():array{$mem=$this->meminfo();$cpu=$this->cpu();return ['load'=>sys_getloadavg(),'memory_total'=>$mem['MemTotal']??0,'memory_available'=>$mem['MemAvailable']??0,'swap_total'=>$mem['SwapTotal']??0,'swap_free'=>$mem['SwapFree']??0,'cpu_steal_percent'=>$cpu,'disk_free'=>disk_free_space(dirname(__DIR__,2))?:0];} private function meminfo():array{$out=[];foreach(file('/proc/meminfo',FILE_IGNORE_NEW_LINES)?:[]as$l)if(preg_match('/^(\w+):\s+(\d+)/',$l,$m))$out[$m[1]]=(int)$m[2]*1024;return $out;} private function cpu():float{$line=(string)(file('/proc/stat',FILE_IGNORE_NEW_LINES)[0]??'');$v=array_map('intval',array_slice(preg_split('/\s+/',trim($line)),1));$total=array_sum($v);$steal=$v[7]??0;$previous=$this->cpu;$this->cpu=[$total,$steal];return $previous&&$total>$previous[0]?round((($steal-$previous[1])/($total-$previous[0]))*100,2):0.0;} }
